// app/Http/Controllers/Api/UserController.php (~70 lines)
namespace App\Http\Controllers\Api;

use App\Actions\User\CreateUserAction;
use App\Actions\User\UpdateUserAction;
use App\DTOs\User\CreateUserDTO;
use App\DTOs\User\UpdateUserDTO;
use App\Http\Controllers\Controller;
use App\Http\Requests\CreateUserRequest;
use App\Http\Requests\UpdateUserRequest;
use App\Http\Resources\UserResource;
use App\Models\User;

class UserController extends Controller
{
    public function index()
    {
        $users = User::query()
            ->when(request('search'), fn ($q, $search) =>
                $q->where('name', 'like', "%{$search}%"))
            ->paginate();
        return UserResource::collection($users);
    }

    public function store(CreateUserRequest $request, CreateUserAction $action)
    {
        $user = $action->execute(CreateUserDTO::fromRequest($request));
        return new UserResource($user);
    }

    public function show(User $user)
    {
        $this->authorize('view', $user);
        return new UserResource($user);
    }

    public function update(UpdateUserRequest $request, User $user, UpdateUserAction $action)
    {
        $this->authorize('update', $user);
        $user = $action->execute($user, UpdateUserDTO::fromRequest($request));
        return new UserResource($user);
    }
}
